#!/usr/bin/env node

/**
 * Extract `--help` text from a Greentic CLI binary and emit an auto-generated
 * reference page under `src/content/docs/reference/cli/<cli>.md`.
 *
 * The page recurses one level into subcommands so short-living teams can
 * inspect the full surface without firing the binary. Curated pages in
 * `src/content/docs/cli/*.mdx` stay untouched — this script only writes under
 * `src/content/docs/reference/cli/`.
 *
 * Usage:
 *   node scripts/sync-cli-help.mjs --cli gtc
 *   node scripts/sync-cli-help.mjs --cli gtc --binary /custom/path/gtc
 *   node scripts/sync-cli-help.mjs --cli greentic-start --depth 0
 *
 * Options:
 *   --cli <name>      Required. Name of the CLI as documented (e.g. `gtc`).
 *   --binary <path>   Optional. Path to the binary. Defaults to --cli on PATH.
 *   --depth <n>       Max subcommand recursion depth (default 1). 0 disables.
 *   --output <path>   Override output path. Defaults to
 *                     src/content/docs/reference/cli/<cli>.md
 *   --dry-run         Print to stdout instead of writing.
 *
 * Exit codes:
 *   0   OK (wrote file OR --dry-run printed)
 *   2   CLI binary not found / exits non-zero on --help
 */

import { execFile } from "child_process";
import { promisify } from "util";
import fs from "fs/promises";
import path from "path";
import { fileURLToPath } from "url";
import { parseArgs } from "util";

const execFileAsync = promisify(execFile);

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT_DIR = path.join(__dirname, "..");
const DEFAULT_OUTPUT_DIR = path.join(
  ROOT_DIR,
  "src",
  "content",
  "docs",
  "reference",
  "cli",
);

const { values: args } = parseArgs({
  options: {
    cli: { type: "string" },
    binary: { type: "string" },
    depth: { type: "string", default: "1" },
    output: { type: "string" },
    "dry-run": { type: "boolean", default: false },
  },
});

if (!args.cli) {
  console.error("FAIL: --cli <name> is required");
  process.exit(2);
}

const cliName = args.cli;
const binary = args.binary || cliName;
const maxDepth = Math.max(0, parseInt(args.depth, 10) || 0);
const outputPath =
  args.output || path.join(DEFAULT_OUTPUT_DIR, `${cliName}.md`);

async function runHelp(argv) {
  try {
    const { stdout, stderr } = await execFileAsync(binary, argv, {
      maxBuffer: 10 * 1024 * 1024,
      env: { ...process.env, NO_COLOR: "1", CLICOLOR: "0" },
    });
    return stdout.trim() || stderr.trim();
  } catch (err) {
    // Some clap CLIs print --help to stderr and exit 0, or exit 2 for subcmd
    // not-found. Prefer whatever came through.
    const out = (err.stdout || "").trim();
    const errOut = (err.stderr || "").trim();
    if (out) return out;
    if (errOut && !errOut.toLowerCase().includes("not found")) return errOut;
    throw err;
  }
}

function extractSubcommands(helpText) {
  // clap's standard `--help` output ends with a `Commands:` block listing
  // subcommand names and their one-line summaries. We parse that block.
  const lines = helpText.split("\n");
  const startIdx = lines.findIndex((l) => /^Commands:\s*$/.test(l));
  if (startIdx === -1) return [];

  const subcommands = [];
  for (let i = startIdx + 1; i < lines.length; i++) {
    const line = lines[i];
    if (!line.trim()) break; // end of Commands block
    // Subcommand lines are indented with 2 spaces: "  name   description"
    const match = line.match(/^\s{2}(\S+)\b/);
    if (!match) continue;
    const name = match[1];
    if (name === "help") continue; // skip built-in clap help subcmd
    subcommands.push(name);
  }
  return subcommands;
}

function fenced(text, lang = "text") {
  return "```" + lang + "\n" + text + "\n```";
}

async function renderPage() {
  const rootHelp = await runHelp(["--help"]);
  let version;
  try {
    version = (await runHelp(["--version"])).trim();
  } catch {
    version = "";
  }

  const lines = [];
  lines.push("---");
  lines.push(`title: ${cliName} CLI reference`);
  lines.push(
    `description: Auto-generated --help reference for the ${cliName} CLI.`,
  );
  lines.push("sidebar:");
  lines.push(`  label: ${cliName}`);
  lines.push("  order: 10");
  lines.push("---");
  lines.push("");
  lines.push(
    `{/* AUTO-GENERATED by scripts/sync-cli-help.mjs — do not edit by hand. */}`,
  );
  lines.push(
    `{/* Curated narrative for this CLI lives under src/content/docs/cli/. */}`,
  );
  lines.push("");
  if (version) {
    lines.push(`**Binary version:** \`${version}\``);
    lines.push("");
  }
  lines.push(
    "This page mirrors the CLI's `--help` output so it stays accurate against the installed binary. If you're looking for narrative and examples, see the curated pages linked in the sidebar.",
  );
  lines.push("");
  lines.push("## Root help");
  lines.push("");
  lines.push(fenced(rootHelp));
  lines.push("");

  if (maxDepth > 0) {
    const subcommands = extractSubcommands(rootHelp);
    if (subcommands.length > 0) {
      lines.push("## Subcommands");
      lines.push("");
      for (const sub of subcommands) {
        let subHelp;
        try {
          subHelp = await runHelp([sub, "--help"]);
        } catch (err) {
          console.warn(
            `[sync-cli-help] ${cliName} ${sub} --help failed: ${err.message.split("\n")[0]}`,
          );
          continue;
        }
        lines.push(`### \`${cliName} ${sub}\``);
        lines.push("");
        lines.push(fenced(subHelp));
        lines.push("");
      }
    }
  }

  return lines.join("\n");
}

async function main() {
  let rendered;
  try {
    rendered = await renderPage();
  } catch (err) {
    console.error(`FAIL: could not render ${cliName} reference: ${err.message}`);
    process.exit(2);
  }

  if (args["dry-run"]) {
    process.stdout.write(rendered);
    return;
  }

  await fs.mkdir(path.dirname(outputPath), { recursive: true });
  await fs.writeFile(outputPath, rendered, "utf8");
  console.log(`[sync-cli-help] wrote ${path.relative(ROOT_DIR, outputPath)}`);
}

main();
